INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (1, '呂布', 'リョフ', 5, 7, 164, 65, 122, 42, 3.37, 0.33, 2.24, 0.24, '三国時代', '後漢末の武将。董卓に仕えたのち自立するが、曹操に敗れ処刑された。武勇で名高い。', 1);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (2, '張巡', 'チョウジュン', 5, 7, 93, 122, 140, 86, 1.18, 1.94, 2.65, 1.57, '唐', '唐の武将。安史の乱で睢陽を守り抜き、徹底抗戦して忠義を示した。', 2);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (3, '趙雲', 'チョウウン', 5, 7, 144, 87, 105, 59, 2.76, 0.96, 1.8, 0.71, '三国時代', '三国時代の蜀の武将。劉備に仕え、長坂坡で単騎奮戦し名声を得た。', 3);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (4, '岳飛', 'ガクヒ', 5, 7, 150, 93, 108, 60, 2.92, 1.12, 1.71, 0.7, '南宋', '南宋の名将。金と戦い連戦連勝するが、秦檜の讒言で処刑された忠臣。', 4);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (5, '蘇定方', 'ソテイホウ', 5, 7, 130, 94, 118, 65, 2.53, 1.18, 2.04, 0.86, '唐', '唐の名将。高句麗・百済遠征で活躍し、唐の版図拡大に貢献した。', 5);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (6, '后羿', 'コウゲイ', 5, 7, 145, 70, 97, 52, 2.65, 0.71, 1.73, 0.66, '神話時代', '古代神話の英雄。九つの太陽を射落としたと伝わる伝説的弓の名手。', 6);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (7, '孫武', 'ソンブ', 5, 7, 91, 148, 110, 96, 1.02, 2.71, 1.84, 1.89, '春秋時代', '春秋時代の兵法家。『孫子』を著し、呉王に仕えて軍制改革を行った。', 7);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (8, '楊戩', 'ヨウセン', 5, 7, 126, 126, 100, 76, 2.0, 2.0, 1.71, 1.3, '神話（道教）', '道教神話の神。二郎真君とも呼ばれ、妖魔退治の英雄として信仰される。', 8);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (9, '陸遜', 'リクソン', 5, 7, 84, 154, 108, 100, 0.88, 3.0, 2.04, 2.04, '三国時代', '三国時代の呉の名将。夷陵の戦いで劉備軍を破り大勝した。', 9);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (10, '梁紅玉', 'リョウコウギョク', 5, 6, 124, 86, 114, 97, 2.37, 1.1, 2.1, 1.92, '南宋', '南宋の女将。韓世忠の妻で、金軍との戦いで鼓を打ち士気を高めた。', 10);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (11, '典韋', 'テンイ', 5, 6, 131, 72, 124, 53, 2.14, 0.61, 2.49, 0.62, '三国時代', '三国時代の魏の武将。曹操を守って戦死し、豪勇で知られる。', 11);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (12, '于謙', 'ウケン', 5, 6, 88, 127, 131, 90, 1.06, 1.92, 2.41, 1.6, '明', '明の政治家。土木の変後に北京を守り、国家再建に尽力した忠臣。', 12);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (13, '伍子胥', 'ゴシショ', 5, 6, 121, 98, 119, 68, 2.12, 1.06, 2.2, 0.93, '春秋時代', '春秋時代の呉の重臣。父兄の仇を討ち、呉を強国へ導いた。', 13);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (14, '賈詡', 'カク', 5, 6, 70, 142, 109, 103, 0.65, 2.59, 2.04, 2.0, '三国時代', '三国時代の魏の謀士。的確な献策で曹操を補佐した知将。', 14);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (15, '常遇春', 'ジョウグウシュン', 5, 6, 135, 73, 104, 59, 2.45, 0.88, 1.94, 0.79, '明', '明建国の功臣。朱元璋に従い各地を平定した猛将。', 15);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (16, '廉頗', 'レンパ', 5, 6, 119, 100, 119, 69, 1.73, 1.16, 1.84, 1.1, '春秋時代', '戦国時代の趙の名将。長平以前の名将で藺相如との和解も有名。', 16);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (17, '秦瓊', 'シンケイ', 5, 6, 133, 80, 107, 60, 2.39, 1.0, 2.08, 0.85, '唐', '唐建国の功臣。勇猛な武将として凌煙閣二十四功臣に列せられた。', 17);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (18, '樊噲', 'ケンカイ', 5, 6, 131, 76, 113, 57, 2.31, 0.78, 1.94, 0.76, '前漢初期', '前漢初期の武将。劉邦を助け楚漢戦争で活躍した豪勇の士。', 18);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (19, '王彦章', 'オウゲンショウ', 5, 6, 132, 80, 102, 60, 2.45, 0.84, 1.76, 0.77, '五代十国', '五代十国の後梁の武将。勇猛で晋軍と戦った。', 19);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (20, '冉閔', 'ゼンビン', 5, 6, 129, 79, 111, 61, 2.35, 0.86, 2.1, 0.81, '五胡十六国', '五胡十六国時代の君主。胡漢対立の中で漢人政権を樹立した。', 20);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (21, '龐統', 'ホウトウ', 5, 6, 72, 141, 108, 100, 0.27, 2.55, 2.14, 2.1, '三国時代', '三国時代の蜀の軍師。鳳雛と称されるが落鳳坡で戦死。', 21);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (22, '黄忠', 'コウチュウ', 5, 6, 131, 78, 95, 60, 2.16, 0.71, 1.31, 0.83, '三国時代', '三国時代の蜀の老将。定軍山で夏侯淵を討ち名を上げた。', 22);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (23, '華佗', 'カダ', 5, 6, 84, 130, 110, 92, 1.08, 2.27, 1.96, 1.72, '三国時代', '後漢末の名医。麻沸散を用いた外科手術で知られる。', 23);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (24, '呂雉', 'リョチ', 5, 6, 60, 138, 96, 103, 0.55, 2.67, 1.92, 2.04, '前漢初期', '前漢初期の皇后。劉邦死後に実権を握った。', 24);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (25, '李広', 'リコウ', 5, 6, 136, 82, 98, 60, 2.51, 0.51, 1.22, 0.64, '前漢', '前漢の名将。匈奴討伐で勇名を馳せた飛将軍。', 25);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (26, '李存孝', 'リソンコウ', 5, 6, 146, 67, 98, 50, 2.8, 0.57, 1.65, 0.48, '五代十国', '五代十国の猛将。李克用に仕えた豪勇で伝説的存在。', 26);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (27, '趙匡胤', 'チョウキョウイン', 5, 6, 129, 91, 102, 62, 2.35, 1.02, 1.55, 0.83, '北宋建国期', '北宋の初代皇帝。陳橋の変で即位し宋を建国。', 27);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (28, '衛青', 'エンセイ', 5, 6, 132, 88, 108, 62, 2.47, 0.92, 1.8, 0.72, '前漢', '前漢の名将。匈奴を討ち武帝の信任を得た。', 28);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (29, '戚継光', 'セキケイコウ', 5, 6, 132, 88, 100, 63, 2.53, 1.08, 1.41, 0.83, '明', '明の名将。倭寇討伐と軍制改革で功績を挙げた。', 29);
INSERT OR IGNORE INTO warriors (id, name, reading, rarity, cost, atk, int, guts, pol, atk_growth, int_growth, guts_growth, pol_growth, era, biography, sort_order) VALUES (30, '穆桂英', 'ボクケイエイ', 5, 6, 130, 87, 92, 62, 2.65, 0.8, 1.27, 0.72, '北宋（伝説）', '北宋伝説の女将。楊家将物語で活躍する英雄。', 30);

