-- Skills
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (1, '天下無双', NULL, NULL, 'パッシブ', '距離2以下の目標に与える全ダメージ18%（45%)増加、距離2以上の攻撃から受ける全ダメージ11%（20%）減少する。同時に3部隊以上から攻撃を受ける時、ダメージ増加効果は無効となる', 1);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (2, '百歩先の戟をも中てる', NULL, '弓のみ', 'パッシブ', '部隊の与える全ダメージが11%（20%）（武力加算）上昇し、移動中の目標へ命中率12%（30%）上昇。自部隊より高い位置にいる目標への命中率は21%（30%）上昇する。', 2);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (3, '危機にも怯まず', NULL, NULL, 'パッシブ', '部隊の全被ダメ減少 5.5%（10%）減少。直前2秒間に攻撃を受けた敵部隊から受けた攻撃数に応じてさらに2%増加（最大11.5%【25％】まで上昇）', 3);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (4, '孤城を固守', NULL, NULL, 'パッシブ', '部隊の全被ダメ6%【15％】（胆力補正）減少。【隣接】に存在する敵1部隊につき、ダメージ軽減効果が追加増加 3.5%【8%】', 4);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (5, '槍、龍の如く出る', NULL, NULL, '連鎖', '通常攻撃後、25%の確率で敵部隊に1~3回の武功ダメージ 75%【165%】を与える。槍兵系兵種の場合、2～3回となる。', 5);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (6, '単騎単馬', NULL, NULL, 'パッシブ', '【隣接】に存在する敵部隊1部隊につき、部隊の全与ダメ5.5%【10%】上昇（武力補正）、最大で15%【60%】まで上昇', 6);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (7, '怒髪冠を衝く', NULL, NULL, '連鎖', '通常攻撃後、26％【35％】の確率で敵部隊に武功ダメージ 。115%【250％】、敵の怒気を3.5【8】減少。自身は○○状態の影響を受けなくなる。効果は2秒間持続', 7);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (8, '岳家槍陣', NULL, '槍のみ', 'パッシブ', '騎兵からの全被ダメ6.5%【20％】減少（胆力補正）、騎兵に与える全与ダメ6.5%【20％】増加（武力補正）', 8);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (9, '東征西討', NULL, NULL, '怒気技', '主将時、怒気100以上で全怒気を消費し、【前方扇形範囲】内最大4部隊に武攻ダメージ 550%【1000% 怒気補正】、敵1部隊毎にダメージ率-60%', 9);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (10, '千里を転戦', NULL, '弓以外', 'パッシブ', '戦闘状態にない時、移動速度+55【100】。【隣接】に存在する味方または友軍部隊1部隊につき、部隊の全与ダメを5.5%【10%】（武力補正）上昇させる。最大で45%まで', 10);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (11, '矢神', '弓のみ', NULL, 'パッシブ', '自身の通常攻撃クリティカル率を5.5%【10%】上昇。通常攻撃の対象の【隣接】の1部隊の敵部隊に追加で通常攻撃ダメージ 35%【80％】を与える。追加ダメージは連鎖を発動しない。', 11);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (12, '日を射る', NULL, '弓のみ', 'パッシブ', '部隊のアクティブスキルおよび怒気技のクリティカル率が6.5%【20%】上昇。対象部隊の高度が自身より高い場合、さらにアクティブスキルと怒気技のクリティカル率が18.5%【50％】増加（武力補正）', 12);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (13, '敵を克し勝利を掴む', NULL, NULL, 'パッシブ', '部隊の有利兵種効果が10.5%【15%】増加する（知力補正）', 13);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (14, '兵は常に形無し', NULL, NULL, 'パッシブ', '部隊がダメージを受ける際、不利兵種による被ダメ増加の影響を受けず、与ダメ時の有利兵種効果が12%【30%】増加する。（知力補正）', 14);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (15, '八九玄功', NULL, NULL, 'パッシブ', '自身のダメージを与える時、30%【75%】の確率で敵の被ダメ減少効果を無視し、さらに自分は10レベルごとに追加で10ポイントの能力を獲得する。自身が40レベルの際、第2スキルレベルが+1、45レベルの際は第3スキルレベルが+1、50レベルの際は第2、第3レベルがさらに+1される。', 15);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (16, '九転の元功', NULL, NULL, 'パッシブ', '部隊は全てのデバフ状態を無効化し、ダメージを受ける度、そのダメージ元の部隊に対して全被ダメを2%減少（胆力補正）。ダメージ元1部隊あたり2秒ごとに1回まで最大で12%【30%】減少。戦闘離脱まで持続', 16);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (17, '連営の火', NULL, NULL, '能動', '25%の確率で発動し、敵軍部隊に知攻ダメージ 120%【300%】を与え、かつマスを【燃焼】状態（ダメージ90%【180%】）にする。持続時間4秒間。2秒後、燃焼は燃焼していない敵軍がいるマスに優先して蔓延する。持続時間4秒間。最大2回まで拡大可能。対象マスがすでに燃焼状態なら、知攻ダメージ 120%【300%】を与え、さらに500の固定兵力ダメージ（兵科影響あり）を追加で与える。', 17);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (18, '絶境から生還', NULL, NULL, 'パッシブ', '部隊が兵力上限x32%【50%】以下の時、2秒ごとに部隊の兵力が一定量回復する（回復率 70%【250%】知力補正）。非戦闘時でも回復可能。出征前の兵力が10000を超える場合、致命ダメージを受けた時に【ダメージ無効】と【免疫】状態に入り、12秒持続し、100秒以内に再発動できない。', 18);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (19, '阻撃戦', '弓以外', NULL, 'パッシブ', '【円形範囲】内の敵部隊が攻撃後、自身未移動時37%【100%】確率で攻撃元に武攻ダメージ 55%【100%】、前2秒に受けた攻撃1部隊毎に12%【30%】追加。最大60%【150%】2秒毎に1部隊最大1回発動。反撃スキル', 19);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (20, '生々と絶えず', NULL, NULL, 'パッシブ', '部隊が300兵力回復するごとに、部隊の与ダメージが1%【10%】増加（武力補正）。最大で55%【100%】。同時に部隊の被ダメを1%【10%】減少。2秒間持続。効果は重ねがけ可能。', 20);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (21, '陣を叫ぶ', NULL, NULL, '能動', '11.5%【25%】の確率で発動し、自身の【円形範囲】内の2部隊の敵部隊を【挑発】状態にし、部隊に【通常攻撃被ダメージ軽減】状態を付与し、受ける通常攻撃ダメージを23％【50%】軽減し、4秒間持続', 21);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (22, '一人で関を守る', NULL, NULL, 'パッシブ', '部隊が攻撃対象となった際、敵部隊の連鎖スキル発動率が6％【15%】減少します。（胆力補正）', 22);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (23, '君に忠じて道を守る', NULL, NULL, 'パッシブ', '【隣接】の味方部隊被ダメージ時、部隊が22%【40%】のダメージを肩代わりする。（ダメージの22%【40%】軽減。胆力補正）。他効果発動不可', 23);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (24, '城を固めて守る', NULL, NULL, 'パッシブ', '部隊が弓兵から受ける全ダメージが32%【50%】減少（胆力補正）し、弓兵以外から受ける全ダメージ6.5%【20%】減少する。（胆力補正）', 24);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (25, '目には目を', NULL, NULL, 'パッシブ', '２秒ごとに敵部隊へ武攻ダメージ 30%を与え、さらに目標部隊が直前2秒間に行った通常攻撃の回数ごとにダメージ率が加算され、1回ごとに追加13%【40%】ダメージ率が上昇します。', 25);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (26, '暴に以って暴を制す', NULL, NULL, 'パッシブ', '直近10秒以内に目標部隊からのダメージを受けている場合、その部隊に対して与える全ダメージが12%【30%】増加します。（武力補正）', 26);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (27, '必殺策', NULL, NULL, '能動', '26%【35%】の確率で発動し、まず目標部隊が自身から得ている【中毒】状態を処理し、その後、敵部隊を【中毒】状態（ダメージ率87%【150%】）にし、6秒間持続', 27);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (28, '一策も洩らさず', NULL, NULL, 'パッシブ', '部隊の全ての武将はアクティブスキルを発動するたびに、その発動した武将の武力と知力が13【40】（知力補正）上昇し、2秒間持続する', 28);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (29, '猛志常に在り', NULL, NULL, 'パッシブ', '部隊の怒気下限が23【50】まで上昇し、怒気の自然回復速度は2秒ごとに5に減少する', 29);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (30, '功を求めて命を奮う', NULL, NULL, 'パッシブ', '部隊が直前10秒以内に失った兵力が13000を超える場合、部隊の全ダメージのクリティカル率が55%【100%】上昇し、クリティカルダメージが55%【100%】（武力補正）増加する。', 30);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (31, '動かざること山の如し', NULL, NULL, 'パッシブ', '戦闘開始後、2秒ごとに1層の【属性上昇】状態を獲得し、自身の武力・知力・胆力が5増加する。この効果は最大3【12】層まで重複可能。層数が3層を超えると挑発状態を無効化する。移動するたびに層数はリセットされる。', 31);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (32, '老いて益々壮健', NULL, NULL, 'パッシブ', '部隊の負傷率が19%【10%】減少し、【治療禁止】状態となる。受ける全ダメージが11%【20%】減少し、与える全ダメージが11%【20%】（武力補正）上昇する。', 32);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (33, '玄甲鉄騎', NULL, NULL, 'パッシブ', '部隊が受ける武攻ダメージが7%【25%】減少し、知攻ダメージ（被ダメ）が19%【10%】増加する。また、距離が1を超える全ダメージについては、さらに15%減少する。', 33);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (34, '百戦の奇略', NULL, NULL, 'パッシブ', '部隊の残兵力が60%以上の場合、与える全ダメージが12%【30%】（武力補正）上昇し、それ未満の場合は受ける全ダメージが11%【20%】減少する。', 34);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (35, '刀を鳴らし犬を屠る', NULL, NULL, 'パッシブ', '部隊の全武将がダメージを与える時、敵部隊の胆力6%【15%】を無視する。', 35);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (36, '破竹の勢い', NULL, NULL, 'パッシブ', '部隊の連鎖スキル発動率が5%上昇し、連鎖スキルダメージが6.5%【20%】（武力補正）増加する。', 36);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (37, '鉄槍で敵を破る', NULL, NULL, '連鎖', '通常攻撃後、30%の確率で敵部隊に武攻ダメージ 95%【230％】を与え、敵の全武将を〇〇状態にし、胆力を6【15】減少させる。効果4秒間持続', 37);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (38, '鉄胆の槍塊', NULL, NULL, 'パッシブ', '部隊所属の全武将は、各行動ごとに30%【75％】の確率（武力補正）で【連撃】状態を2秒間獲得します。刀兵系・騎兵系兵種の場合、連撃発動率が15%減少し、弓兵系兵種の場合は連撃発動率が40%減少します。各武将ごとに個別判定されます。', 38);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (39, '怒って万軍を破る', NULL, NULL, '怒気技', '主将時に怒気110以上の時、全怒気を消費し、【円形範囲】内の最大6部隊に武攻ダメージ 315%【540%】（怒気補正）を与え、3部隊以上の部隊にダメージを与えた場合、怒気回復効率を50%上昇させ、次にこのスキルを発動するまで持続する。', 39);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (40, '短兵接近戦', NULL, '弓以外', 'パッシブ', '【隣接】の敵部隊に与えるアクティブ及び連鎖ダメージを12.5%【35%】（武力補正）上昇させる', 40);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (41, '烈火天を覆う', NULL, NULL, '怒気技', '主将時に怒気100以上の時、全怒気を消費し、自身前方【直線範囲】内の敵部隊に智攻ダメージ 325%【550%】（怒気補正）、対象が燃焼タイル上にいる場合、ダメージ率は670%【1300%】。タイルを【燃焼】状態（ダメージ率90%【180%】）にし、8秒間持続', 41);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (42, '焼き尽くす', NULL, '兵器含む', 'パッシブ', '部隊が器械および建築物に与える全ダメージが65%【200％】増加します。（知力補正）', 42);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (43, '万箭同時に放つ', '弓のみ', NULL, '能動', '31%【40%】の確率で発動し、対象部隊及びその【隣接】の敵部隊に武功ダメージ 86%【140%】を与え、敵部隊が1部隊多いごとにダメージ率が20%減少し、最大80%まで減少する。', 43);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (44, '弱点を攻破', NULL, NULL, 'パッシブ', '敵部隊に異なるデバフ状態が1種類あるごとに、その部隊への全ダメージが3.7%【10%】増加（武力補正）。最大で50%まで', 44);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (45, '骨の削りて傷を癒す', NULL, NULL, '能動', '21%【30%】の確率で発動し、部隊の兵力を一定回復 220%【400%】（知力補正）、さらに自身部隊が【免疫】状態を4秒間獲得', 45);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (46, '神医', NULL, NULL, 'パッシブ', '部隊の負傷率+1%【10%】、回復効果が35%【80%】増加する（知力補正）', 46);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (47, '計は深く、思いは遠し', NULL, NULL, '連鎖', '通行攻撃後、32%【50%】の確率で敵部隊に知攻ダメージ 66%【120%】を与え、対象部隊の全ての強化状態を解除する。', 47);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (48, '天下に範を示す母儀', NULL, NULL, 'パッシブ', '部隊が与える全ダメージが6%【15%】増加します。（知力補正）。さらに5怒気ごとに追加で1%増加します。', 48);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (49, '猿臂の弓名人', '弓のみ', NULL, 'パッシブ', '自身の通常攻撃に貫通効果が付与され、攻撃範囲内で同一直線かつ同じ高さにいる最大4つの敵部隊に通常攻撃ダメージを与える。ダメージ率 80%/57%【120%】/90%【180%】/115%【250%】の順となる。連鎖は最初にダメージを受けた部隊のみ発動する。', 49);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (50, '飛将軍', NULL, NULL, 'パッシブ', '部隊が受ける全ダメージが13%【40%】（胆力補正）減少します。部隊が何らかのダメージを与えた後は、被ダメージ減少効果が消失し、代わりに全ダメージが11%【20%】（武力補正）増加します。この効果は戦闘終了まで持続します。', 50);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (51, '将を斬り旗を奪う', '全', NULL, '能動', '31%【40%】の確率で発動し、敵部隊に武攻ダメージ 95%【230%】を与える。直前2秒間の兵力損失が2000を超える場合、ダメージ率は225%【450%】となる。', 51);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (52, '十騎で城を奪う', NULL, NULL, 'パッシブ', '部隊の兵力が目標部隊の43.5%【30%】以上の時、その部隊に与える全ダメージが出生時の初期兵力を基準として計算される。', 52);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (53, '太祖長拳', NULL, NULL, '能動', '31%【40%】の確率で発動し、敵部隊に武功ダメージ 110%【200%】を与える。前回と同じ攻撃対象なら、このスキルのダメージ率が6%【15%】増加（最大15回まで重複）。攻撃対象が異なる場合、ダメージ率増加効果はリセットされる。', 53);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (54, '一杯の酒で権を釈す', NULL, '弓以外', 'パッシブ', '部隊がアクティブスキルで直接ダメージを与えた時、追加で65【200】兵力（武力補正）分の固定ダメージを与える。間接ダメージ効果時は追加ダメージ18.5【50】兵力の固定ダメージとなる。', 54);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (55, '黄龍を一直線に攻める', NULL, NULL, '能動', '30%の確率で発動し、敵部隊に武攻ダメージ 120%【300%】を与え、【隣接】の敵部隊数＞1かつ隣接に味方または友軍部隊がいない場合、ダメージ率は225%【450%】となる。', 55);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (56, '致命の突撃', NULL, '馬のみ', 'パッシブ', '部隊が突撃状態（移動速度が兵種基礎速度以上かつ10秒間維持）で初めて攻撃する時、部隊兵力x1.1%【2%】分の固定ダメージを追加で与える。', 56);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (57, '正を以って奇となす', NULL, NULL, 'パッシブ', '部隊全武将がアクティブスキルまたは連鎖スキルを発動するたびに、自身の与ダメージが5.5%【10%】上昇し、ダメージを与える際に敵の胆力6%【15%】を無視する。2秒間持続し、効果は重複可能。', 57);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (58, '鴛鴦陣', NULL, NULL, 'パッシブ', '【円形範囲】内の味方槍兵部隊が与えるダメージを6%【15%】（武力補正）上昇させ、味方刀兵部隊が受ける回復効果を12%【30%】上昇させ、味方弓兵部隊のクリティカル率を+5.5%【10%】する。', 58);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (59, '援攻', NULL, NULL, 'パッシブ', '行軍時、最初の2秒間に自身の【隣接】に存在し対象にダメージを与えた味方または友軍部隊が1部隊存在するごとに、自身が13%【40%】の確率で追加で1回の通常攻撃を行い、各部隊ごとに独立判定され、最大で3回の追加通常攻撃が可能。', 59);
INSERT OR IGNORE INTO skills (id, name, color, weapon_restriction, skill_type, description, sort_order) VALUES (60, '軍師を務める', NULL, NULL, 'パッシブ', '怒気スキル発動後、部隊が受ける全ダメージが22%【40％】減少（胆力補正）、減少効果は2秒ごとに4%ずつ減少する。', 60);

